101	void Android::init() {
102	    preLoad();
103	    trunk = android::Property::GetInt32("ro.build.version.trunk");
104	    sdk = android::Property::GetInt32("ro.build.version.sdk");
105	    if (trunk > Sdk2Trunk(sdk)) {
106	        LOGW("current trunk(%d) no match sdk(%d).\n", trunk, sdk);
107	        int trunk_size = sizeof(kTrunkData) / sizeof(kTrunkData[0]);
108	        for (int cur = sdk + 1; cur < trunk_size; ++cur) {
109	            if (trunk == kTrunkData[cur]) {
110	                sdk = cur;
111	                break;
112	            }
113	        }
114	    }
115	    release = android::Property::Get("ro.build.version.release", INVALID_VALUE);
116	    sscanf(release.c_str(), "%*d.%*d.%d", &patch);
117	    id = android::Property::Get("ro.build.id", INVALID_VALUE);
118	    name = android::Property::Get("ro.product.name", INVALID_VALUE);
119	    model = android::Property::Get("ro.product.model", INVALID_VALUE);
120	    manufacturer = android::Property::Get("ro.product.manufacturer", INVALID_VALUE);
121	    brand = android::Property::Get("ro.product.brand", INVALID_VALUE);
122	    hardware = android::Property::Get("ro.hardware", INVALID_VALUE);
123	    abis = android::Property::Get("ro.product.cpu.abilist", INVALID_VALUE);
124	    incremental = android::Property::Get("ro.build.version.incremental", INVALID_VALUE);
125	    security = android::Property::Get("ro.build.version.security_patch", INVALID_VALUE);
126	    type = android::Property::Get("ro.build.type", INVALID_VALUE);
127	    tag = android::Property::Get("ro.build.tags", INVALID_VALUE);
128	    fingerprint = android::Property::Get("ro.build.fingerprint", INVALID_VALUE);
129	    time = android::Property::Get("ro.build.date.utc", INVALID_VALUE);
130	    debuggable = android::Property::Get("ro.debuggable", INVALID_VALUE);
131	    preLoadLater();
132	}
