200	void Android::preLoadLater() {
201	    if (Sdk() > Q) {
202	        realLibart = (CoreApi::Bits() == 64) ? LIBART64 : LIBART32;
203	    } else {
204	        if (Sdk() > P) {
205	            realLibart = (CoreApi::Bits() == 64) ? LIBART64_LV29 : LIBART32_LV29;
206	        } else {
207	            realLibart = (CoreApi::Bits() == 64) ? LIBART64_LV28 : LIBART32_LV28;
208	        }
209	    }
210	
211	    LOGI("Switch android(%d) env.\n", sdk);
212	    for (const auto& listener : mSdkListeners) {
213	        listener->execute(sdk);
214	    }
215	    if (RESETINI) RESETINI();
216	}
