218	void Android::oatPreLoadLater() {
219	    LOGI("Switch oat version(%d) env.\n", oat_header_.kOatVersion);
220	    for (const auto& listener : mOatListeners) {
221	        listener->execute(oat_header_.kOatVersion);
222	    }
223	    if (RESETINI) RESETINI();
224	}
