236	void Android::OnSdkChanged(int sdk) {
237	    if (sdk >= M) {
238	        // do nothing
239	    } else if (sdk >= 1) {
240	        LOGE("Invaild sdk(%d)\n", sdk);
241	        return;
242	    } else {
243	        sdk = 0;
244	        LOGI("remove android-sdk env\n");
245	    }
246	    INSTANCE->onSdkChanged(sdk);
247	}
