257	void Android::onSdkChanged(int current_sdk) {
258	    if (sdk != current_sdk) {
259	        sdk = current_sdk;
260	        preLoadLater();
261	        if (instance_.Ptr()) {
262	            instance_.CleanCache();
263	            instance_ = 0x0;
264	        }
265	    }
266	}
