313	void Android::ForeachStaticField(art::mirror::Class& clazz, std::function<bool (art::ArtField& field)> fn) {
314	    if (LIKELY(Sdk() >= W)) {
315	        uint32_t size = clazz.NumFields();
316	        if (!size) return;
317	        art::ArtField field(clazz.GetFields(), clazz);
318	        int i = 0;
319	        do {
320	            if (field.IsStatic())
321	                if (fn(field)) break;
322	            field.MovePtr(SIZEOF(ArtField));
323	            i++;
324	        } while(i < size);
325	    } else {
326	        uint32_t size = clazz.NumStaticFields();
327	        if (!size) return;
328	        art::ArtField field(clazz.GetSFields(), clazz);
329	        int i = 0;
330	        do {
331	            if (fn(field)) break;
332	            field.MovePtr(SIZEOF(ArtField));
333	            i++;
334	        } while(i < size);
335	    }
336	}
