19	Android::BasicType Android::SignatureToBasicTypeAndSize(const char* sig, uint64_t* size_out) {
20	    char c = sig[0];
21	    Android::BasicType ret;
22	    uint64_t size;
23	
24	    switch (c) {
25	        case '[':
26	        case 'L':
27	            ret = basic_object;
28	            size = 4;
29	            break;
30	        case 'Z':
31	            ret = basic_boolean;
32	            size = 1;
33	            break;
34	        case 'C':
35	            ret = basic_char;
36	            size = 2;
37	            break;
38	        case 'F':
39	            ret = basic_float;
40	            size = 4;
41	            break;
42	        case 'D':
43	            ret = basic_double;
44	            size = 8;
45	            break;
46	        case 'B':
47	            ret = basic_byte;
48	            size = 1;
49	            break;
50	        case 'S':
